// Fusion et parsing des flux RSS Les Echos + BFM Business
const KEYWORDS = [
  'investissement', 'opportunité', 'économie', 'entreprise', 'fiscalité',
  'immobilier', 'bourse', 'startup', 'financement', 'taux', 'inflation',
  'croissance', 'marché', 'budget', 'impôt', 'CAC', 'PME', 'ETI',
  'crypto', 'bitcoin', 'banque', 'crédit', 'épargne', 'retraite'
];

function parseRSS(xmlText, sourceName) {
  const items = [];
  const itemRegex = /<item>([\s\S]*?)<\/item>/g;
  let match;
  while ((match = itemRegex.exec(xmlText)) !== null) {
    const itemContent = match[1];
    const titleMatch = itemContent.match(/<title>(?:<!\[CDATA\[)?([^\]<]+)(?:\]\]>)?<\/title>/);
    const descMatch = itemContent.match(/<description>(?:<!\[CDATA\[)?([^\]<]+)(?:\]\]>)?<\/description>/);
    const linkMatch = itemContent.match(/<link>([^<]+)<\/link>/);
    const pubDateMatch = itemContent.match(/<pubDate>([^<]+)<\/pubDate>/);

    if (titleMatch) {
      items.push({
        title: titleMatch[1].trim(),
        description: descMatch ? descMatch[1].trim().substring(0, 200) : '',
        link: linkMatch ? linkMatch[1].trim() : '',
        pubDate: pubDateMatch ? pubDateMatch[1].trim() : '',
        source: sourceName
      });
    }
  }
  return items.slice(0, 15);
}

const inputs = $input.all();
let lesEchosXML = '';
let bfmXML = '';

for (const item of inputs) {
  const data = item.json.data || item.json;
  if (typeof data === 'string') {
    if (data.includes('lesechos') || item.json.url && item.json.url.includes('lesechos')) {
      lesEchosXML = data;
    } else {
      bfmXML = data;
    }
  }
}

// Parser les deux flux
const lesEchosArticles = parseRSS(lesEchosXML, 'Les Echos');
const bfmArticles = parseRSS(bfmXML, 'BFM Business');

// Fusionner et filtrer par mots-clés
const allArticles = [...lesEchosArticles, ...bfmArticles];

const filtered = allArticles.filter(article => {
  const text = (article.title + ' ' + article.description).toLowerCase();
  return KEYWORDS.some(kw => text.includes(kw.toLowerCase()));
});

// Prendre les 5 meilleurs (les plus récents après filtrage)
const top5 = filtered.slice(0, 5);

if (top5.length === 0) {
  // Fallback : prendre les 5 premiers sans filtre
  const fallback = allArticles.slice(0, 5);
  const summary = fallback.map((a, i) => `${i+1}. [${a.source}] ${a.title}`).join('\n');
  return [{ json: { articlesSummary: summary, count: fallback.length, filtered: false } }];
}

const summary = top5.map((a, i) => `${i+1}. [${a.source}] ${a.title}\n   ${a.description}`).join('\n\n');

return [{ json: { articlesSummary: summary, count: top5.length, filtered: true } }];

const response = $input.first().json;

let postText = '';
if (response.message && response.message.content) {
  postText = response.message.content;
} else if (response.choices && response.choices[0]) {
  postText = response.choices[0].message.content;
} else if (typeof response === 'string') {
  postText = response;
} else {
  postText = JSON.stringify(response);
}

const now = new Date();
const dateStr = now.toLocaleDateString('fr-FR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return [{
  json: {
    instagram_caption: postText.trim(),
    generated_at: now.toISOString(),
    date_fr: dateStr,
    source: 'veille-quotidienne',
    workflow: 'La Verticale — Veille Instagram'
  }
}];

